5. Return ONLY the raw code. Do not include explanations, markdown backticks, or conversational text.

You are generating Python code. Please follow PEP8 style and use type hints.
The reference solution of that problem in Typescript is 
function solve(n: number, m: number, k: number): number {
    if (k === 0) {
        return n * m; // Each cell needs its own sensor
    }

    // If the sensor can cover the entire grid, only one is needed
    if (k >= Math.min(n, m) / 2) {
        return 1;
    }

    // For a grid, the minimum number of sensors required is ceil(n / (k + 1)) * ceil(m / (k + 1))
    // Because each sensor can cover a (2k + 1) x (2k + 1) area
    const rows = Math.ceil(n / (k + 1));
    const cols = Math.ceil(m / (k + 1));

    return rows * cols;
}

